// Extract form data and validate
const formData = $json.body;

// Required fields
const required = [
  'board',
  'class',
  'subject',
  'chapter',
  // 'exam_type',
  // 'total_marks',
  // 'duration'
];

const missing = required.filter(field => !formData[field]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Map full subject names to abbreviations
const subjectMap = {
    "Physical Science": "PS",
    "Biological Science": "Bio",
    "Social Studies": "SS",
    "Mathematics": "Maths",
    "Telugu": "Telugu",
    "Hindi": "Hindi",
    "English": "English"
};

// Pick abbreviation if exists
const subjectAbbrev = subjectMap[formData.subject.trim()] || formData.subject.trim();

// Construct Board_Class_Subject_Chapter
const boardClassSubjectChapter = `${formData.board.trim()}_${formData.class}_${subjectAbbrev}_${formData.chapter.trim()}`;

// Clean and structure output
return {
  json: {
    board: formData.board.trim(),
    class: parseInt(formData.class),
    subject: formData.subject.trim(),
    subject_abbrev: subjectAbbrev,           // added for reference
    chapter: formData.chapter.trim(),
    board_class_subject_chapter: boardClassSubjectChapter, // dynamic filter
    exam_type: formData.exam_type.trim(),
    total_marks: parseInt(formData.total_marks),
    duration: parseInt(formData.duration),
    language: formData.language || 'English',
    teacher_email: formData.teacher_email,
    teacher_whatsapp: formData.teacher_whatsapp,
    school_name: formData.school_name || 'Unknown School',
    timestamp: new Date().toISOString(),
    request_id: 'REQ_' + Date.now()
  }
};

// Inputs
const exam = $node["Extract & Validate Form Data"].json;
const boardPattern = $node["Get Board Marks Pattern"].json;
const syllabus = $node["Lookup Chapter Syllabus"].json;

// Parse marks pattern like "1:40,2:20,4:30,8:10"
let pattern = {};
if (boardPattern && boardPattern.Marks_Distribution) {
  boardPattern.Marks_Distribution.split(',').forEach(part => {
    const [marks, perc] = part.split(':');
    pattern[parseInt(marks)] = parseInt(perc);
  });
}

// default if nothing found
if (Object.keys(pattern).length === 0) {
  pattern = {1:40, 2:30, 4:20, 8:10};
}

// Calculate question count per mark
const dist = {};
let remaining = exam.total_marks;

for (const [marks, perc] of Object.entries(pattern)) {
  const marksTotal = Math.floor(exam.total_marks * (perc/100));
  const qCount = Math.floor(marksTotal / parseInt(marks));
  if (qCount > 0) {
    dist[marks] = {
      questions: qCount,
      total_marks: qCount * parseInt(marks)
    };
    remaining -= dist[marks].total_marks;
  }
}

// allocate any leftover marks to the smallest mark value
if (remaining > 0) {
  const minMarks = Math.min(...Object.keys(pattern).map(Number));
  if (!dist[minMarks]) dist[minMarks] = { questions: 0, total_marks: 0 };
  const extraQs = Math.floor(remaining / minMarks);
  dist[minMarks].questions += extraQs;
  dist[minMarks].total_marks += extraQs * minMarks;
  remaining -= extraQs * minMarks;
}

// Topics and outcomes
const topics = syllabus && syllabus.Topics
  ? syllabus.Topics.split(',').map(t => t.trim())
  : [exam.chapter];

return [{
  json: {
    exam,
    syllabus: {
      topics,
      outcomes: syllabus?.Learning_Outcomes || '',
      difficulty: syllabus?.Difficulty_Levels || 'easy:40,medium:40,hard:20'
    },
    distribution: dist
  }
}];

