// Extract JSON text from AI output
let aiText = $json.candidates[0].content.parts[0].text.trim();

// Remove ```json ... ``` if present
aiText = aiText.replace(/^```json/, "").replace(/```$/, "").trim();

// Parse into JSON
let examData = JSON.parse(aiText);

// Build Word-compatible HTML
let html = `
<html>
<head>
  <style>
    body { font-family: 'Times New Roman', serif; line-height: 1.6; font-size: 12pt; }
    h1, h2 { text-align: center; }
    table { width: 100%; border-collapse: collapse; margin-bottom: 10px; }
    td { padding: 4px; vertical-align: top; }
    .instructions { margin: 10px 0; }
    .section { margin: 15px 0; }
    .section-title { font-weight: bold; margin: 10px 0; }
  </style>
</head>
<body>
  <h1>${examData.exam.board}</h1>
  <h2>${examData.exam.subject}</h2>

  <table border="1">
    <tr>
      <td><b>Class:</b> ${examData.exam.class}</td>
      <td><b>Chapter:</b> ${examData.exam.chapter}</td>
    </tr>
    <tr>
      <td><b>School:</b> ${examData.exam.school}</td>
      <td><b>Exam Type:</b> ${examData.exam.exam_type}</td>
    </tr>
    <tr>
      <td><b>Maximum Marks:</b> ${examData.exam.total_marks}</td>
      <td><b>Duration:</b> ${examData.exam.duration} minutes</td>
    </tr>
  </table>

  <h2>QUESTION PAPER</h2>

  <div class="instructions">
    <b>Instructions:</b>
    <ol>
      ${examData.instructions.map(i => `<li>${i}</li>`).join("")}
    </ol>
  </div>

  ${examData.sections.map(section => `
    <div class="section">
      <p class="section-title">${section.title}</p>
      ${section.questions.map((q, idx) => `<p>${idx + 1}. ${q}</p>`).join("")}
    </div>
  `).join("")}
</body>
</html>
`;

// Return to next node
return {
  json: {
    html: html
  }
};

// Access values from the "Extract & Validate Form Data" node
const formData = $node["Extract & Validate Form Data"].json;
// Access values safely
const exam = formData.exam || formData;

let rawHtml = $json.html;

// Remove duplicate headers (keep only sections & instructions)
rawHtml = rawHtml.replace(/<h1[\s\S]*?<\/table>/i, ""); 
rawHtml = rawHtml.replace(/<h2>QUESTION PAPER<\/h2>/i, "");

// Ensure PART A/B/C titles are bold if not styled by AI
rawHtml = rawHtml.replace(/<p>(PART [A-Z][\s\S]*?)<\/p>/gi, "<p class='section-title'>$1</p>");

// Master compact template
const htmlTemplate = `
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body {
      font-family: 'Times New Roman', serif;
      margin: 0.7cm;
      font-size: 11pt;
      line-height: 1.1;
      color: #000;
    }
    h1, h2 {
      text-align: center;
      margin: 0.1cm 0;
    }
    h1 { font-size: 14pt; font-weight: bold; text-transform: uppercase; }
    h2 { font-size: 12pt; font-weight: bold; }

    table {
      width: 100%;
      border-collapse: collapse;
      margin: 0.2cm 0;
      font-size: 10.5pt;
    }
    td {
      border: 1px solid #000;
      padding: 2px 4px;
      vertical-align: top;
      width: 50%;
    }
    td b { display: inline-block; width: 40%; }

    .divider {
      border-top: 1px solid #000;
      margin: 0.15cm 0;
    }
    .qp-title {
      text-align: center;
      font-weight: bold;
      font-size: 12pt;
      margin: 0.1cm 0;
      letter-spacing: 0.3px;
    }
    .section-title {
      font-weight: bold;
      margin: 0.08cm 0;
      text-decoration: underline;
    }
    ol { padding-left: 0.6cm; margin: 0; }
    p { margin: 0.03cm 0; }

    /* Single A4 page control */
    @page {
      size: A4;
      margin: 1cm;
    }
  </style>
</head>
<body>

  <h1>${exam.school_name.toUpperCase()}</h1>
  <h2>${exam.board}</h2>

  <table>
    <tr>
      <td><b>Class:</b> ${exam.class}</td>
      <td><b>Chapter:</b> ${exam.chapter}</td>
    </tr>
    <tr>
      <td><b>Subject:</b> ${exam.subject}</td>
      <td><b>Exam Type:</b> ${exam.exam_type}</td>
    </tr>
    <tr>
      <td><b>Maximum Marks:</b> ${exam.total_marks}</td>
      <td><b>Duration:</b> ${exam.duration} minutes</td>
    </tr>
  </table>

  <div class="divider"></div>
  <div class="qp-title">QUESTION PAPER</div>
  <div class="divider"></div>

  ${rawHtml}

</body>
</html>
`;

// Generate clean filename
const fileName = `${exam.subject} - ${exam.exam_type} - Class ${exam.class} - ${exam.chapter}.doc`;

return {
  json: {},
  binary: {
    data: {
      data: Buffer.from(htmlTemplate, "utf-8"),
      fileName: fileName,
      mimeType: "application/msword"
    }
  }
};
